
"use client"

import { useState, useMemo } from "react";
import Link from "next/link";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Trophy, Medal, MapPin, Zap, Flame, Crown, Loader2, Clock, Navigation, Map as MapIcon, Star, Ghost } from "lucide-react";
import { cn } from "@/lib/utils";
import { useFirestore, useCollection, useMemoFirebase } from "@/firebase";
import { collection, query, where, orderBy, limit } from "firebase/firestore";
import { RenderCarIcon } from "@/components/icons/car-icons";
import { Button } from "@/components/ui/button";

const KOSOVO_CITIES = [
  "Mbarë Kosova", "Prishtinë", "Prizren", "Pejë", "Gjakovë", "Mitrovicë", "Gjilan", "Ferizaj", 
  "Vushtrri", "Podujevë", "Rahovec", "Fushë Kosovë", "Suharekë", "Kaçanik", 
  "Skënderaj", "Lipjan", "Malishevë", "Drenas", "Deçan", "Klinë", "Kamenicë", 
  "Dragash", "Istog", "Viti", "Obiliq", "Leposaviq", "Graçanicë", "Hani i Elezit", 
  "Zveçan", "Shtime", "Novobërdë", "Zubin Potok", "Junik", "Mamushë", 
  "Ranillug", "Partesh", "Kllokot"
];

export default function LeaderboardPage() {
  const [activeTab, setActiveTab] = useState("top-speed");
  const [cityFilter, setCityFilter] = useState("Mbarë Kosova");
  const db = useFirestore();

  const rankingResetDate = useMemo(() => {
    const d = new Date('2024-05-22T00:00:00.000Z'); 
    return d.toISOString();
  }, []);

  const publicRunsQuery = useMemoFirebase(() => {
    if (!db) return null;
    return query(
      collection(db, "public_runs"),
      where("createdAt", ">=", rankingResetDate),
      orderBy("createdAt", "desc"),
      limit(500)
    );
  }, [db, rankingResetDate]);

  const { data: allRuns, isLoading } = useCollection(publicRunsQuery);

  const filteredRuns = useMemo(() => {
    if (!allRuns) return [];
    if (cityFilter === "Mbarë Kosova") return allRuns;
    return allRuns.filter(run => run.city === cityFilter);
  }, [allRuns, cityFilter]);

  const topSpeedRankings = useMemo(() => {
    const uniqueUsers: Record<string, any> = {};
    filteredRuns.forEach(run => {
      if (!uniqueUsers[run.userId] || run.peakSpeedKmH > uniqueUsers[run.userId].peakSpeedKmH) {
        uniqueUsers[run.userId] = run;
      }
    });
    return Object.values(uniqueUsers).sort((a: any, b: any) => b.peakSpeedKmH - a.peakSpeedKmH);
  }, [filteredRuns]);

  const distanceRankings = useMemo(() => {
    const userTotals: Record<string, any> = {};
    filteredRuns.forEach(run => {
      if (!userTotals[run.userId]) {
        userTotals[run.userId] = { 
          ...run, 
          totalDistanceMeters: 0,
          totalRuns: 0 
        };
      }
      userTotals[run.userId].totalDistanceMeters += run.distanceMeters || 0;
      userTotals[run.userId].totalRuns += 1;
    });
    return Object.values(userTotals).sort((a: any, b: any) => b.totalDistanceMeters - a.totalDistanceMeters);
  }, [filteredRuns]);

  const weeklyFastest = topSpeedRankings[0] || null;

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 overflow-x-hidden no-scrollbar relative">
      <div className="absolute top-0 left-0 right-0 h-64 bg-gradient-to-b from-accent/10 via-accent/5 to-transparent pointer-events-none" />
      
      <div className="p-8 pb-4 relative z-10 space-y-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-accent/10 rounded-2xl flex items-center justify-center">
              <Trophy className="w-6 h-6 text-accent" />
            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tighter uppercase italic leading-none">RANKINGU</h1>
              <p className="text-[10px] text-muted-foreground uppercase font-bold tracking-[0.3em] mt-1">LIVE KOSOVA</p>
            </div>
          </div>
        </div>

        <div className="space-y-2">
          <Label className="text-[9px] font-black uppercase text-muted-foreground px-1 tracking-widest">FILTRO SIPAS QYTETIT</Label>
          <Select value={cityFilter} onValueChange={setCityFilter}>
            <SelectTrigger className="w-full h-12 glass border-white/10 rounded-2xl font-black italic uppercase text-xs">
              <SelectValue placeholder="Zgjidh Qytetin" />
            </SelectTrigger>
            <SelectContent className="glass border-white/10 max-h-[300px]">
              {KOSOVO_CITIES.map(c => (
                <SelectItem key={c} value={c} className="font-bold text-xs uppercase italic">{c}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      <div className="px-6 space-y-4 relative z-10">
        {isLoading ? (
          <Card className="p-12 flex items-center justify-center glass rounded-[3rem] border-white/5">
            <Loader2 className="w-8 h-8 animate-spin text-accent" />
          </Card>
        ) : (
          <>
            {weeklyFastest && cityFilter === "Mbarë Kosova" && (
              <Card className="relative overflow-hidden border-accent/20 bg-gradient-to-br from-yellow-500/10 to-transparent p-6 rounded-[2.5rem] shadow-2xl group transition-all border-l-4 border-l-yellow-500">
                <div className="absolute top-0 right-0 p-6 opacity-10">
                  <Flame className="w-20 h-20 text-yellow-500 animate-pulse" />
                </div>
                <div className="relative z-10 flex flex-col gap-4">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-yellow-500 animate-pulse" />
                    <span className="text-[10px] font-black uppercase tracking-[0.3em] text-yellow-500">MBRETI I KOSOVËS</span>
                  </div>
                  <div className="flex items-center justify-between">
                    <Link href={`/profile/${weeklyFastest.userId}`} className="flex items-center gap-4">
                      <div className="w-14 h-14 rounded-2xl bg-zinc-950 border border-yellow-500/20 flex items-center justify-center">
                         <RenderCarIcon type={weeklyFastest.profileIcon} className="w-8 h-8 text-yellow-500" />
                      </div>
                      <div>
                        <h3 className="text-lg font-black italic uppercase tracking-tighter">{weeklyFastest.username}</h3>
                        <div className="flex items-center gap-1.5 mt-0.5">
                          <MapPin className="w-3 h-3 text-accent" />
                          <span className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest">{weeklyFastest.city}</span>
                        </div>
                      </div>
                    </Link>
                    <div className="text-right">
                      <div className="text-3xl font-black italic text-yellow-500">{weeklyFastest.peakSpeedKmH}</div>
                      <div className="text-[9px] font-black text-muted-foreground uppercase">KM/H</div>
                    </div>
                  </div>
                </div>
              </Card>
            )}
          </>
        )}
      </div>

      <Tabs defaultValue="top-speed" onValueChange={setActiveTab} className="w-full px-6 mt-8 relative z-10">
        <TabsList className="grid w-full grid-cols-2 glass border-white/5 h-14 rounded-[2rem] p-1.5">
          <TabsTrigger value="top-speed" className="rounded-2xl data-[state=active]:bg-accent data-[state=active]:text-background font-black text-[10px] uppercase italic">SHPEJTËSI</TabsTrigger>
          <TabsTrigger value="distance" className="rounded-2xl data-[state=active]:bg-accent data-[state=active]:text-background font-black text-[10px] uppercase italic">DISTANCË</TabsTrigger>
        </TabsList>

        <TabsContent value="top-speed" className="mt-8 space-y-4">
          {topSpeedRankings.length > 0 ? (
            topSpeedRankings.map((run: any, index: number) => (
              <LeaderboardCard key={run.id} driver={{ ...run, name: run.username, car: `${run.carBrand} ${run.carModel}` }} index={index} metric={`${run.peakSpeedKmH} km/h`} hasTelemetry={!!run.telemetry} runId={run.id} />
            ))
          ) : !isLoading && (
            <div className="text-center py-24 text-muted-foreground glass rounded-[3rem] border-white/5 opacity-50">
              <Zap className="w-10 h-10 mx-auto mb-4 opacity-10" />
              <p className="text-[11px] font-black uppercase tracking-[0.4em]">Nuk ka rekorde për {cityFilter}.</p>
            </div>
          )}
        </TabsContent>

        <TabsContent value="distance" className="mt-8 space-y-4">
           {distanceRankings.length > 0 ? (
            distanceRankings.map((run: any, index: number) => (
              <LeaderboardCard 
                key={run.userId} 
                driver={{ ...run, name: run.username, car: `${run.carBrand} ${run.carModel}` }} 
                index={index} 
                metric={`${(run.totalDistanceMeters / 1000).toFixed(1)} km`} 
                subMetric={`${run.totalRuns} gara`}
              />
            ))
          ) : !isLoading && (
            <div className="text-center py-24 text-muted-foreground glass rounded-[3rem] border-white/5 opacity-50">
              <Navigation className="w-10 h-10 mx-auto mb-4 opacity-10" />
              <p className="text-[11px] font-black uppercase tracking-[0.4em]">Nuk ka gara për {cityFilter}.</p>
            </div>
          )}
        </TabsContent>
      </Tabs>
      <BottomNav />
    </div>
  );
}

function LeaderboardCard({ driver, index, metric, subMetric, hasTelemetry, runId }: { driver: any, index: number, metric: string, subMetric?: string, hasTelemetry?: boolean, runId?: string }) {
  return (
    <Card className={cn(
      "glass-card border-white/5 p-5 relative overflow-hidden group transition-all duration-300 rounded-[2.5rem] mb-4",
      index === 0 && "border-accent/40 bg-accent/[0.03]"
    )}>
      <div className="flex items-center gap-5 relative z-10">
        <div className="flex flex-col items-center justify-center min-w-[36px]">
          {index === 0 ? <Trophy className="w-7 h-7 text-accent" /> : 
           index === 1 ? <Medal className="w-7 h-7 text-zinc-400" /> :
           index === 2 ? <Medal className="w-7 h-7 text-orange-600" /> :
           <span className="text-xl font-black text-muted-foreground/30 italic">#{index + 1}</span>}
        </div>
        
        <Link href={`/profile/${driver.userId}`} className="w-14 h-14 rounded-[1.5rem] bg-zinc-950 border border-white/10 flex items-center justify-center shadow-lg active:scale-95 transition-transform">
           <RenderCarIcon type={driver.profileIcon} className="w-8 h-8 text-accent" />
        </Link>

        <div className="flex-1 min-w-0">
          <h3 className="font-black text-sm truncate uppercase italic tracking-tight">{driver.name}</h3>
          <div className="flex items-center gap-1.5">
            <MapPin className="w-2.5 h-2.5 text-accent opacity-50" />
            <span className="text-[8px] font-black text-muted-foreground uppercase tracking-widest">{driver.city}</span>
          </div>
          <p className="text-[9px] font-bold text-muted-foreground truncate uppercase tracking-widest mt-0.5">{driver.car}</p>
        </div>

        <div className="text-right">
          <div className="text-2xl font-black italic text-accent leading-none">
            {metric.split(' ')[0]}
          </div>
          <div className="text-[9px] font-black text-muted-foreground uppercase tracking-widest mt-1">{metric.split(' ')[1]}</div>
          {subMetric && <div className="text-[8px] font-bold text-accent/60 uppercase mt-0.5">{subMetric}</div>}
        </div>
      </div>
    </Card>
  );
}
