"use client"

import Link from "next/link";
import { usePathname } from "next/navigation";
import { Gauge, Trophy, Radio, User } from "lucide-react";
import { cn } from "@/lib/utils";

const NAV_ITEMS = [
  { label: "Ranking", icon: Trophy, href: "/leaderboard" },
  { label: "Trip", icon: Gauge, href: "/dashboard", primary: true },
  { label: "Radarët", icon: Radio, href: "/explore" },
  { label: "Profili", icon: User, href: "/profile" },
];

export function BottomNav() {
  const pathname = usePathname();

  return (
    <div className="fixed bottom-0 left-0 right-0 mx-auto max-w-md h-[5.5rem] glass border-t border-white/5 px-8 flex items-center justify-around z-[100] rounded-t-[2.5rem] shadow-[0_-10px_40px_rgba(0,0,0,0.5)] safe-bottom-padding">
      {NAV_ITEMS.map((item) => {
        const isActive = pathname === item.href;
        const Icon = item.icon;

        if (item.primary) {
          return (
            <Link key={item.href} href={item.href} className="relative -top-7 active:scale-95 transition-transform duration-200">
              <div className={cn(
                "w-[4.5rem] h-[4.5rem] rounded-[2rem] flex items-center justify-center transition-all duration-300 neon-glow border-4 border-background shadow-2xl",
                isActive ? "bg-accent scale-110" : "bg-zinc-900 border-zinc-800"
              )}>
                <Icon className={cn("w-10 h-10 transition-colors", isActive ? "text-background" : "text-accent")} />
              </div>
              <span className={cn(
                "text-[10px] absolute -bottom-7 left-1/2 -translate-x-1/2 font-black uppercase tracking-[0.1em] transition-colors whitespace-nowrap",
                isActive ? "text-accent" : "text-muted-foreground"
              )}>
                {item.label}
              </span>
            </Link>
          );
        }

        return (
          <Link key={item.href} href={item.href} className="flex flex-col items-center gap-1.5 group active:scale-90 transition-transform duration-200">
            <div className={cn(
              "w-10 h-10 rounded-2xl flex items-center justify-center transition-all",
              isActive ? "bg-accent/10" : "group-hover:bg-white/5"
            )}>
              <Icon className={cn(
                "w-6 h-6 transition-colors",
                isActive ? "text-accent neon-text" : "text-muted-foreground group-hover:text-foreground"
              )} />
            </div>
            <span className={cn(
              "text-[9px] font-black uppercase tracking-widest transition-colors",
              isActive ? "text-accent" : "text-muted-foreground"
            )}>
              {item.label}
            </span>
          </Link>
        );
      })}
    </div>
  );
}
